import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"DeerFlow Architecture Analysis","description":"","frontmatter":{"title":"DeerFlow Architecture Analysis","status":"complete","category":"super-agent-harness"},"headers":[],"relativePath":"research/agents/deer-flow/index.md","filePath":"research/agents/deer-flow/index.md"}'),r={name:"research/agents/deer-flow/index.md"};function o(i,e,l,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="deerflow" tabindex="-1">DeerFlow <a class="header-anchor" href="#deerflow" aria-label="Permalink to &quot;DeerFlow&quot;">​</a></h1><blockquote><p>An open-source <strong>super agent harness</strong> by ByteDance that orchestrates sub-agents, memory, and sandboxes to do almost anything — powered by extensible skills built on LangGraph.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>DeerFlow (<strong>D</strong>eep <strong>E</strong>xploration and <strong>E</strong>fficient <strong>R</strong>esearch <strong>Flow</strong>) is an open-source project by ByteDance released under the MIT license. It started as a deep-research framework (v1) and was rewritten from scratch as a fully-fledged <strong>super agent harness</strong> in v2 (launched February 2026).</p><p>Unlike the CLI coding agents in this research corpus, DeerFlow is not a coding-first tool — it is a <strong>general-purpose runtime</strong> that gives AI agents the infrastructure to get complex, long-horizon work done: research, report generation, slide creation, data pipelines, dashboards, and code tasks. The v2 rewrite was triggered by community usage patterns: developers were pushing v1 far beyond deep research, and it became clear the system needed to become a proper harness rather than a narrow research framework.</p><p>DeerFlow is built on <strong>LangGraph + LangChain</strong>, runs on <strong>Python (backend) + Next.js (frontend)</strong>, and ships batteries-included: filesystem, memory, skills, sandboxed execution, and sub-agent spawning are all built in.</p><p><strong>Key characteristics:</strong></p><ul><li><strong>Super agent harness</strong> — not a framework you wire together; a batteries-included runtime</li><li><strong>Skills-as-Markdown</strong> — a &quot;skill&quot; is a <code>.md</code> file defining a workflow, loaded on-demand</li><li><strong>Progressive skill loading</strong> — only loads what the task needs; keeps context window lean</li><li><strong>Sandboxed execution</strong> — each task runs inside an isolated Docker container</li><li><strong>Dynamic sub-agents</strong> — lead agent spawns sub-agents on the fly; parallel when possible</li><li><strong>Long-term memory</strong> — persistent across sessions; per-user profile, preferences, knowledge</li><li><strong>IM channel dispatch</strong> — receive tasks from Telegram, Slack, Feishu/Lark</li><li><strong>MCP server support</strong> — extensible tool ecosystem via Model Context Protocol</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><strong>URL</strong>: <a href="https://github.com/bytedance/deer-flow" target="_blank" rel="noreferrer">https://github.com/bytedance/deer-flow</a></li><li><strong>Language</strong>: Python (backend), TypeScript/Next.js (frontend)</li><li><strong>License</strong>: MIT</li><li><strong>Version</strong>: 2.0 (ground-up rewrite; v1 was deep-research only)</li><li><strong>Stars</strong>: ~20 K+ (reached #1 GitHub Trending on Feb 28, 2026 at v2 launch)</li><li><strong>Organization</strong>: ByteDance</li><li><strong>Website</strong>: <a href="https://deerflow.tech" target="_blank" rel="noreferrer">https://deerflow.tech</a></li></ul><h2 id="architecture-summary" tabindex="-1">Architecture Summary <a class="header-anchor" href="#architecture-summary" aria-label="Permalink to &quot;Architecture Summary&quot;">​</a></h2><p>DeerFlow is split into three runtime layers with a unified proxy front:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Client (Next.js, port 3000) / IM Channels           │</span></span>
<span class="line"><span>│  Telegram · Slack · Feishu (no public IP needed)     │</span></span>
<span class="line"><span>└───────────────────┬─────────────────────────────────┘</span></span>
<span class="line"><span>                    │ Unified proxy (port 2026)</span></span>
<span class="line"><span>          ┌─────────┴──────────┐</span></span>
<span class="line"><span>          │                    │</span></span>
<span class="line"><span>┌─────────▼──────┐   ┌─────────▼──────────────────────┐</span></span>
<span class="line"><span>│  Gateway API   │   │  LangGraph Server (port 2024)   │</span></span>
<span class="line"><span>│  (port 8001)   │   │  Lead Agent (graph-based)        │</span></span>
<span class="line"><span>│  Skill install │   │  Sub-agent spawning              │</span></span>
<span class="line"><span>│  Follow-up gen │   │  Session management              │</span></span>
<span class="line"><span>│  IM dispatch   │   │  Streaming responses             │</span></span>
<span class="line"><span>└────────────────┘   └──────────────┬─────────────────┘</span></span>
<span class="line"><span>                                    │</span></span>
<span class="line"><span>                     ┌──────────────▼──────────────┐</span></span>
<span class="line"><span>                     │  Sandbox (Docker container) │</span></span>
<span class="line"><span>                     │  /mnt/skills/public         │</span></span>
<span class="line"><span>                     │  /mnt/skills/custom         │</span></span>
<span class="line"><span>                     │  /mnt/user-data/uploads     │</span></span>
<span class="line"><span>                     │  /mnt/user-data/workspace   │</span></span>
<span class="line"><span>                     │  /mnt/user-data/outputs     │</span></span>
<span class="line"><span>                     └─────────────────────────────┘</span></span></code></pre></div><h2 id="execution-modes" tabindex="-1">Execution Modes <a class="header-anchor" href="#execution-modes" aria-label="Permalink to &quot;Execution Modes&quot;">​</a></h2><p>DeerFlow exposes four execution modes that balance speed vs. capability:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th><th>Sub-Agents</th><th>Use When</th></tr></thead><tbody><tr><td><strong>flash</strong></td><td>Fast, minimal reasoning</td><td>No</td><td>Quick queries, simple lookups</td></tr><tr><td><strong>standard</strong></td><td>Normal agentic loop</td><td>No</td><td>Most tasks</td></tr><tr><td><strong>pro</strong></td><td>Includes planning phase</td><td>No</td><td>Complex multi-step tasks</td></tr><tr><td><strong>ultra</strong></td><td>Full sub-agent fan-out</td><td>Yes</td><td>Long-horizon, parallel research</td></tr></tbody></table><h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><h3 id="skills-system" tabindex="-1">Skills System <a class="header-anchor" href="#skills-system" aria-label="Permalink to &quot;Skills System&quot;">​</a></h3><p>Skills are structured Markdown files (<code>.md</code>) that define a workflow, best practices, and references to supporting resources. DeerFlow ships built-in skills for research, report generation, slide creation, web pages, and image/video generation. Custom skills drop into <code>/mnt/skills/custom</code>. Skills load <strong>progressively</strong> — only when the task needs them — keeping the context window lean.</p><h3 id="sub-agent-orchestration" tabindex="-1">Sub-Agent Orchestration <a class="header-anchor" href="#sub-agent-orchestration" aria-label="Permalink to &quot;Sub-Agent Orchestration&quot;">​</a></h3><p>The lead agent can spawn sub-agents dynamically. Each sub-agent gets its own scoped context, tools, and termination conditions. Sub-agents run in parallel when possible and return structured results. The lead synthesizes all results into a coherent output. See <a href="./agentic-loop.html">agentic-loop.md</a>.</p><h3 id="sandbox-filesystem" tabindex="-1">Sandbox &amp; Filesystem <a class="header-anchor" href="#sandbox-filesystem" aria-label="Permalink to &quot;Sandbox &amp; Filesystem&quot;">​</a></h3><p>Every task runs inside an isolated Docker container with a full filesystem. The agent reads, writes, and edits files; executes bash commands; and views images. All state is auditable. Zero contamination between sessions. See <a href="./tool-system.html">tool-system.md</a>.</p><h3 id="long-term-memory" tabindex="-1">Long-Term Memory <a class="header-anchor" href="#long-term-memory" aria-label="Permalink to &quot;Long-Term Memory&quot;">​</a></h3><p>Persistent cross-session memory: user profile, preferences, writing style, technical stack, recurring workflows. Stored locally; user-controlled.</p><h3 id="mcp-server-support" tabindex="-1">MCP Server Support <a class="header-anchor" href="#mcp-server-support" aria-label="Permalink to &quot;MCP Server Support&quot;">​</a></h3><p>Tools are extensible via MCP servers (HTTP/SSE with OAuth). Swap or add tools without modifying the core harness.</p><h2 id="interesting-patterns" tabindex="-1">Interesting Patterns <a class="header-anchor" href="#interesting-patterns" aria-label="Permalink to &quot;Interesting Patterns&quot;">​</a></h2><ol><li><strong>Skills-as-Markdown</strong> — a capability module is a <code>.md</code> file, not code. Declarative workflow specification that the LLM reads directly.</li><li><strong>Progressive skill loading</strong> — skills load on demand, not all at once. Keeps context lean for token-sensitive models.</li><li><strong>LangGraph native</strong> — orchestration is a typed state graph with checkpointing, time-travel debugging, and durable execution.</li><li><strong>Super agent harness concept</strong> — the distinction between &quot;framework you wire together&quot; vs. &quot;runtime with everything built in.&quot;</li><li><strong>Claude Code integration</strong> — a skill (<code>claude-to-deerflow</code>) lets Claude Code send tasks to DeerFlow; bridges CLI agents with the harness.</li><li><strong>IM channel dispatch without public IP</strong> — uses long-polling (Telegram), Socket Mode (Slack), WebSocket (Feishu). No ngrok required.</li><li><strong>v1→v2 ground-up rewrite</strong> — v1 (deep research only) was extended by the community far beyond its intended scope, prompting a full redesign.</li></ol><h2 id="benchmark-reception" tabindex="-1">Benchmark / Reception <a class="header-anchor" href="#benchmark-reception" aria-label="Permalink to &quot;Benchmark / Reception&quot;">​</a></h2><p>DeerFlow is not measured on traditional coding benchmarks (SWE-bench, Terminal-Bench). Its community traction is the primary signal:</p><ul><li><strong>#1 GitHub Trending</strong> globally on launch day of v2 (Feb 28, 2026)</li><li>Trendshift #1 spot for repositories</li><li>Active community of contributors extending v1 far beyond deep research (the catalyst for v2)</li></ul><h2 id="research-files" tabindex="-1">Research Files <a class="header-anchor" href="#research-files" aria-label="Permalink to &quot;Research Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><a href="./">README.md</a></td><td>This file — overview, architecture, key patterns</td></tr><tr><td><a href="./architecture.html">architecture.md</a></td><td>LangGraph stack, Python/Node.js split, sandbox modes, IM channels</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>Lead agent loop, sub-agent spawning, parallel execution, result synthesis</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>Skills-as-Markdown, progressive loading, MCP, core tools, skill archives</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>Sub-agent context isolation, summarization, filesystem offload</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Super agent harness concept, skills, v1→v2, Claude Code bridge, InfoQuest</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Community reception, GitHub trending, star trajectory</td></tr><tr><td><a href="./references.html">references.md</a></td><td>All links — GitHub, docs, website, guides</td></tr></tbody></table><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://github.com/bytedance/deer-flow" target="_blank" rel="noreferrer">GitHub Repository</a></li><li><a href="https://deerflow.tech" target="_blank" rel="noreferrer">Official Website</a></li><li><a href="./architecture.html">Architecture Deep Dive</a></li><li><a href="./agentic-loop.html">Agent Loop Analysis</a></li><li><a href="./tool-system.html">Tool System / Skills</a></li><li><a href="./context-management.html">Context Management</a></li><li><a href="./unique-patterns.html">Unique Patterns</a></li><li><a href="./references.html">All References</a></li></ul>`,36)])])}const g=t(r,[["render",o]]);export{u as __pageData,g as default};
